const AWS = require('aws-sdk');
const sqs = new AWS.SQS({ region: 'your-region' });
const dynamodb = new AWS.DynamoDB.DocumentClient({ region: 'your-region' });

exports.handler = async (event) => {
  try {
    const order = JSON.parse(event.Records[0].body);
    
    // Call external payment API
    const paymentResponse = await fetch('https://payment-api.com/charge', {
      method: 'POST',
      body: JSON.stringify(order),
      headers: { 'Content-Type': 'application/json' },
    });
    const paymentData = await paymentResponse.json();
    
    // Update DynamoDB with payment data
    const params = {
      TableName: 'orders-table',
      Key: { id: order.id },
      UpdateExpression: 'set #paymentStatus = :status, #paymentData = :data',
      ExpressionAttributeNames: { '#paymentStatus': 'paymentStatus', '#paymentData': 'paymentData' },
      ExpressionAttributeValues: {
        ':status': paymentData.status,
        ':data': paymentData.data,
      },
    };
    await dynamodb.update(params).promise();
    
    console.log(`Order processed successfully: ${order.id}`);
  } catch (error) {
    console.error(error);
  }
};